import{_ as a,c as s,o as t,ae as o}from"./chunks/framework.CDjunVez.js";const b=JSON.parse('{"title":"CLI and Web-Based Access","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/web.md","filePath":"introduction/web.md"}'),n={name:"introduction/web.md"};function r(i,e,c,d,l,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="cli-and-web-based-access" tabindex="-1">CLI and Web-Based Access <a class="header-anchor" href="#cli-and-web-based-access" aria-label="Permalink to &quot;CLI and Web-Based Access&quot;">​</a></h1><p>KiwiPanel provides both <strong>command-line</strong> and <strong>web-based</strong> access, built on the same core system.</p><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><p>The <strong>CLI (<code>kiwipanel</code>)</strong> is the primary interface. It is designed for developers and system administrators who prefer fast, scriptable, and transparent control directly from the terminal.</p><h2 id="web-based-access" tabindex="-1">Web-Based Access <a class="header-anchor" href="#web-based-access" aria-label="Permalink to &quot;Web-Based Access&quot;">​</a></h2><p>The <strong>Web UI</strong> offers a visual interface for common tasks, making day-to-day server management easier. Actions taken in the Web UI map directly to standard Linux services and configuration files, without hiding system behavior. You are encouraged to explore the CLI for more advanced tasks. To access the Web UI, navigate to <code>http://your-server-ip:8443/passcode</code>. <code>passcode</code> is a unique identifier for your server.</p><p>You will see the passcode once after installation or you can find it in the CLI by running <code>kiwipanel passcode</code> (with root access) in case you forget it. Without the passcode, you cannot access the Web UI but get 404 errors.</p><p>The <strong>CLI (<code>kiwipanel</code>)</strong> and <strong>Web UI</strong> are built on the same core system, ensuring consistency and ease of use.</p>',8)])])}const u=a(n,[["render",r]]);export{b as __pageData,u as default};
